const ContactTrigger = () => {
  const [visible, setVisible] = useState(false);
  return (
    <>
      <AddOutlined onClick={() => setVisible(true)} />
      {/* <AddOutlined /> */}
      <ContactDialog visible={visible} onClose={() => setVisible(false)} />
    </>
  );
};

