const UserListItem = () => {
  const [permission, setPermission] = useState('read');
  const config = [
    {
      value: 'read',
      label: '可阅读',
    },
    {
      value: 'write',
      label: '可编辑',
    },
    {
      value: 'remove',
      label: '移除',
    },
  ];
  return (
    <div css={{ display: 'flex', padding: '6px 0' }}>
      <Avatar css={{ marginRight: 14 }} size={32} src={avatarURL} />
      <div css={{ flex: 1 }}>
        <div css={{ fontSize: 14, lineHeight: '20px' }}>陈慕杰</div>
        <div css={{ fontSize: 12, lineHeight: '16px', color: N400 }}>Platform Frontend</div>
      </div>
      <div css={{ width: 112, textAlign: 'right' }}>
        <Dropdown
          trigger={['click']}
          placement="bottomCenter"
          overlay={
            <Menu
              css={{
                minWidth: 'auto',
              }}
              selectedKeys={[permission]}
              onClick={({ key }) => {
                console.log(key);
                setPermission(String(key));
              }}
              onSelect={({ key }) => {
                console.log(key);
                setPermission(String(key));
              }}
            >
              {config.map(item => (
                <Menu.Item key={item.value}>
                  <div
                    css={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between',
                    }}
                  >
                    <span>{item.label}</span>
                    {item.value === permission && <CheckOutlined css={{ marginRight: '0 !important' }} />}
                  </div>
                </Menu.Item>
              ))}
            </Menu>
          }
        >
          <Button type="link" css={{ height: 40, lineHeight: '40px' }}>
            {config.find(o => o.value === permission)?.label}
          </Button>
        </Dropdown>
      </div>
    </div>
  );
};

