const PermissionButton = forwardRef((props: ButtonProps, ref: Ref<HTMLButtonElement>) => (
  <Button ref={ref} type="primary" icon={<LinkCopyOutlined />} {...props}>
    分享
  </Button>
));

const PermissionButtonWithTooltipAndPopover = ({ content }: { content?: ReactNode }) => {
  const [popupStatus, setPopupStatus] = useState<'none' | 'tooltip' | 'popover'>('none');
  return (
    <Popover
      overlayClassName={PopoverClassName}
      className="Popover__className"
      maxWidth={480}
      visible={popupStatus === 'popover'}
      placement="bottomLeft"
      trigger={['click']}
      content={content}
      onVisibleChange={visible => {
        if (visible) {
          setPopupStatus('popover');
        } else {
          setPopupStatus('none');
        }
      }}
      hideArrow
    >
      <Tooltip
        className="Tooltip__className"
        visible={popupStatus === 'tooltip'}
        onVisibleChange={visible => {
          if (visible) {
            if (popupStatus === 'none') {
              setPopupStatus('tooltip');
            }
          } else {
            setPopupStatus('none');
          }
        }}
        placement="bottom"
        overlay="我可以：分享、编辑、评论此文档"
      >
        <Button type="primary" icon={<LinkCopyOutlined />}>
          分享
        </Button>
      </Tooltip>
    </Popover>
  );
};

export default () => {
  const [panel, setPanel] = useState<'main' | 'users' | 'qrcode'>('main');
  return (
    <ConfigProvider locale={zhCN}>
      <Global
        styles={{
          html: {
            fontSize: 14,
          },
          [`.${PopoverClassName}`]: {
            '.ud__popover-content': {
              padding: 0,
            },
          },
          [`.${DialogClassName}`]: {
            '.ud__modal__content': {
              padding: 16,
              '.ud__modal__title': {
                marginBottom: 16,
              },
            },
          },
        }}
      />
      <Space size="large" direction="vertical">
        <>
          <h4>Trigger</h4>
          <PermissionButtonWithTooltipAndPopover
            content={
              panel === 'main' ? (
                <Panel onExpandUsers={() => setPanel('users')} onClickQRCode={() => setPanel('qrcode')} />
              ) : panel === 'users' ? (
                <UsersPanel onBack={() => setPanel('main')} />
              ) : panel === 'qrcode' ? (
                <QRCodePanel onBack={() => setPanel('main')} />
              ) : null
            }
          />
        </>
        <>
          <h4>Button</h4>
          <PermissionButton />
        </>
        <>
          <h4>主 Overlay</h4>
          <Panel />
        </>
        <>
          <h4>协作者 Overlay</h4>
          <UsersPanel />
        </>
        <>
          <h4>扫码分享 Overlay</h4>
          <QRCodePanel />
        </>
      </Space>
    </ConfigProvider>
  );
};
